	openai "github.com/sashabaranov/go-openai"
)

const (
	systemPrompt = `You are an AI assistant with access to tools. Follow these rules:

1. When solving a task, think step by step. Use tools when needed.
2. You have these tools available:
   - calculator: Evaluate mathematical expressions
   - search: Search the web for information (DuckDuckGo)
   - web_fetch: Directly fetch content from any URL (use when search fails)
   - read_docs: Read local files from the computer
   - todo: Manage task lists for complex multi-step tasks
   - weather: Get current weather for any city

3. IMPORTANT: The search tool uses DuckDuckGo which may not work from all regions.
   If search fails, try using web_fetch to query Bing or other search engines directly.
   Examples:
   - https://www.bing.com/search?q=your+query+here
   - https://news.bing.com/news/search?q=your+query
   - https://www.baidu.com/s?wd=your+query

4. For complex tasks, use the todo tool to create a task checklist.
5. When you have enough information, respond directly in natural language.
6. Always separate your thinking from your final answer.
   Use  thinking  tags for your reasoning process.
7. If a tool returns an error, tell the user and suggest alternatives.`
)

// ParsedResponse contains the extracted components of an LLM response.
type ParsedResponse struct {
	Thinking  string     // Extracted thinking/reasoning process
	Text      string     // Final response text
	ToolCalls []ToolCall // Parsed tool calls
}

var tagThinkingRe = regexp.MustCompile(`(?s)` + "```" + `(?:think|reasoning)\s*\n(.*?)(?:\n` + "```" + `|$)`)

// ParseLLMResponse parses an LLM response to extract thinking, tool calls, and final answer.
// It handles multiple formats:
//   - Text-based tool calls: ToolName(param1="value1", param2="value2")
//   - Thinking extraction:  content
//   - Native OpenAI tool calls
func ParseLLMResponse(content string) *ParsedResponse {
	resp := &ParsedResponse{Text: strings.TrimSpace(content)}

	// 1. Extract thinking from special markers.
	if matches := tagThinkingRe.FindStringSubmatch(content); len(matches) > 0 {
		for i := 1; i < len(matches); i++ {
			if matches[i] != "" {
				resp.Thinking = strings.TrimSpace(matches[i])
				resp.Text = strings.TrimSpace(tagThinkingRe.ReplaceAllString(content, ""))
				break
			}
		}
	}

	return resp
}

// Agent is the core agent runtime that orchestrates the LLM loop.
type Agent struct {
	client    *openai.Client
	apiKey    string
	model     string
	registry  *Registry
	sessions  *SessionManager
	ctxMgr    *ContextManager
	maxTurns  int
	LLMApiURL string // base URL for the OpenAI-compatible API
	LastTrace string // last turn's execution trace (for web display)
}

// AgentOption configures the agent.
type AgentOption func(*Agent)

func WithModel(model string) AgentOption {
	return func(a *Agent) { a.model = model }
}

func WithMaxTurns(n int) AgentOption {
	return func(a *Agent) { a.maxTurns = n }
}

func WithLLMApiURL(url string) AgentOption {
	return func(a *Agent) { a.LLMApiURL = url }
}

// NewAgent creates a new agent.
func NewAgent(apiKey string, registry *Registry, opts ...AgentOption) *Agent {
	client := openai.NewClient(apiKey)
	a := &Agent{
		client:    client,
		apiKey:    apiKey,
		model:     "gpt-4o-mini",
		registry:  registry,
		sessions:  NewSessionManager(),
		ctxMgr:    NewContextManager(),
		maxTurns:  10,
		LastTrace: "",
	}
	for _, opt := range opts {
		opt(a)
	}
	if a.LLMApiURL != "" {
		cfg := openai.DefaultConfig(apiKey)
		cfg.BaseURL = a.LLMApiURL
		a.client = openai.NewClientWithConfig(cfg)
	}
	return a
}

// RunResult contains the full result of a single agent run.
type RunResult struct {
	Content   string     `json:"content"`
	Turns     int        `json:"turns"`
	ToolCalls []ToolCall `json:"tool_calls,omitempty"`
	Trace     string     `json:"trace"`
	Error     string     `json:"error,omitempty"`
}

// Run executes one user input through the full agent loop.
func (a *Agent) Run(ctx context.Context, sessionID, userInput string) (*RunResult, error) {
	sess := a.sessions.GetOrCreate(sessionID)

	// Add user message.
	sess.AddUserMessage(userInput)

	// Build trace.
	trace := fmt.Sprintf("[%s] Session %s: %s\n", time.Now().Format(time.RFC3339), sessionID, userInput)
	var allToolCalls []ToolCall

	for turn := 0; turn < a.maxTurns; turn++ {
		// Check context limits.
		if cMsg := a.ctxMgr.CheckAndCompress(sess); cMsg != "" {
			trace += cMsg + "\n"
		}

		// Call LLM.
		llmTrace, toolCalls, response, err := a.callLLM(ctx, sess)
		trace += llmTrace
		if err != nil {
			trace += fmt.Sprintf("LLM error: %v\n", err)
			a.LastTrace = trace
			return &RunResult{
				Trace: trace,
				Error: fmt.Sprintf("LLM call failed: %v", err),
			}, nil
		}

		// Parse the LLM response for thinking content.
		parsed := ParseLLMResponse(response)
		if parsed.Thinking != "" {
			trace += fmt.Sprintf("  [thinking] %s\n", truncate(parsed.Thinking, 300))
		}

		// If no tool calls, the LLM responded directly.
		if len(toolCalls) == 0 {
			sess.AddAssistantMessage(response)
			trace += fmt.Sprintf("  → %s\n", truncate(response, 200))
			a.LastTrace = trace
			return &RunResult{
				Content:   response,
				Turns:     turn + 1,
				ToolCalls: allToolCalls,
				Trace:     trace,
			}, nil
		}

		// LLM wants to call tools.
		var tcms []ToolCallMessage
		for _, tc := range toolCalls {
			tcms = append(tcms, tc.ToolCallMessage)
		}
		sess.AddAssistantToolCallMessage(tcms)

		// Execute each tool.
		var turnToolCalls []ToolCall
		for _, tc := range toolCalls {
			tc.Result, tc.IsError = a.executeToolCall(ctx, &trace, tc)
			sess.AddToolResult(tc.ID, tc.Name, tc.Result, tc.IsError)
			turnToolCalls = append(turnToolCalls, tc)
		}
		allToolCalls = append(allToolCalls, turnToolCalls...)
	}

	// Max turns reached.
	errMsg := fmt.Sprintf("Exceeded maximum turns (%d)", a.maxTurns)
	trace += errMsg + "\n"
	a.LastTrace = trace
	return &RunResult{
		Content:   errMsg,
		Turns:     a.maxTurns,
		ToolCalls: allToolCalls,
		Trace:     trace,
		Error:     errMsg,
	}, nil
}

// safeMsg is our own message struct that omits empty content for tool_calls.
type safeMsg struct {
	Role         string              `json:"role"`
	Content      *string             `json:"content,omitempty"`
	ToolCalls    []openai.ToolCall   `json:"tool_calls,omitempty"`
	ToolCallID   string              `json:"tool_call_id,omitempty"`
}

// buildSafeMessages converts internal messages to safeMsg (control JSON output).
func buildSafeMessages(msgs []map[string]any) []safeMsg {
	var out []safeMsg
	for _, m := range msgs {
		role, _ := m["role"].(string)
		content, _ := m["content"].(string)

		sm := safeMsg{Role: role}

		switch role {
		case "assistant":
			if tcs, ok := m["tool_calls"].([]map[string]any); ok && len(tcs) > 0 {
				// Tool-calls message: content must be omitted/null, not "".
				var tools []openai.ToolCall
				for _, tc := range tcs {
					id, _ := tc["id"].(string)
					tcType, _ := tc["type"].(string)
					fn, _ := tc["function"].(map[string]any)
					fnName, _ := fn["name"].(string)
					fnArgs, _ := fn["arguments"].(string)
					tools = append(tools, openai.ToolCall{
						ID:   id,
						Type: openai.ToolType(tcType),
						Function: openai.FunctionCall{
							Name:      fnName,
							Arguments: fnArgs,
						},
					})
				}
				sm.ToolCalls = tools
				// Content stays nil → omitted from JSON.
			} else if content != "" {
				sm.Content = &content
			}
		case "tool":
			sm.Content = &content
			if tid, ok := m["tool_call_id"].(string); ok {
				sm.ToolCallID = tid
			}
		default:
			// user, system
			if content != "" {
				sm.Content = &content
			}
		}
		out = append(out, sm)
	}
	return out
}

// openaiResponse is the subset of the OpenAI response we need.
type openaiResponse struct {
	Choices []struct {
		Message struct {
			Role      string            `json:"role"`
			Content   string            `json:"content"`
			ToolCalls []openai.ToolCall `json:"tool_calls"`
		} `json:"message"`
		FinishReason string `json:"finish_reason"`
	} `json:"choices"`
	Usage struct {
		PromptTokens     int `json:"prompt_tokens"`
		CompletionTokens int `json:"completion_tokens"`
	} `json:"usage"`
}

// callLLM sends the session messages to the LLM using a raw HTTP request
// so we can control exactly how tool_calls messages are serialized.
func (a *Agent) callLLM(ctx context.Context, sess *Session) (string, []ToolCall, string, error) {
	msgs := sess.ToOpenAIMessages()
	safeMsgs := buildSafeMessages(msgs)

	// Build the request body manually.
	reqBody := map[string]any{
		"model":       a.model,
		"messages":    safeMsgs,
		"tools":       toRequestTools(a.registry.Schemas()),
		"temperature": 0.7,
	}

	jsonBytes, err := json.Marshal(reqBody)
	if err != nil {
		return "", nil, "", fmt.Errorf("failed to marshal request: %w", err)
	}

	// Determine API URL.
	apiURL := a.LLMApiURL
	if apiURL == "" {
		apiURL = "https://api.openai.com/v1"
	}
	apiURL = strings.TrimRight(apiURL, "/")

	httpReq, err := http.NewRequestWithContext(ctx, "POST", apiURL+"/chat/completions", bytes.NewReader(jsonBytes))
	if err != nil {
		return "", nil, "", fmt.Errorf("failed to create request: %w", err)
	}
	httpReq.Header.Set("Content-Type", "application/json")
	httpReq.Header.Set("Authorization", "Bearer "+a.apiKey)

	resp, err := http.DefaultClient.Do(httpReq)
	if err != nil {
		return "", nil, "", fmt.Errorf("API call failed: %w", err)
	}
	defer resp.Body.Close()

	respBody, err := io.ReadAll(resp.Body)
	if err != nil {
		return "", nil, "", fmt.Errorf("failed to read response: %w", err)
	}

	if resp.StatusCode != http.StatusOK {
		return "", nil, "", fmt.Errorf("error, status code: %d, message: %s", resp.StatusCode, string(respBody))
	}

	var result openaiResponse
	if err := json.Unmarshal(respBody, &result); err != nil {
		return "", nil, "", fmt.Errorf("failed to parse response: %w", err)
	}

	if len(result.Choices) == 0 {
		return "", nil, "", fmt.Errorf("empty response from LLM")
	}

	choice := result.Choices[0]
	msg := choice.Message

	trace := fmt.Sprintf("  [LLM] %s (tokens: %d+%d, finish: %s)\n",
		a.model, result.Usage.PromptTokens, result.Usage.CompletionTokens, choice.FinishReason)

	// Parse tool calls.
	if len(msg.ToolCalls) > 0 {
		var calls []ToolCall
		for _, tc := range msg.ToolCalls {
			call := ToolCall{
				ID:   tc.ID,
				Name: tc.Function.Name,
				Args: tc.Function.Arguments,
				ToolCallMessage: ToolCallMessage{
					ID:   tc.ID,
					Type: string(tc.Type),
					Function: struct {
						Name      string "json:\"name\""
						Arguments string "json:\"arguments\""
					}{
						Name:      tc.Function.Name,
						Arguments: tc.Function.Arguments,
					},
				},
			}
			calls = append(calls, call)
			trace += fmt.Sprintf("  [tool call] %s(%s)\n", tc.Function.Name, tc.Function.Arguments)
		}
		return trace, calls, msg.Content, nil
	}

	// Text response.
	return trace, nil, msg.Content, nil
}

// executeToolCall runs a single tool and updates the trace.
func (a *Agent) executeToolCall(ctx context.Context, trace *string, tc ToolCall) (string, bool) {
	start := time.Now()
	result, err := a.registry.Execute(ctx, tc.Name, tc.Args)
	duration := time.Since(start)

	if err != nil {
		*trace += fmt.Sprintf("  [tool error] %s(%s): %v (%v)\n", tc.Name, tc.Args, err, duration)
		return fmt.Sprintf("Error: %v", err), true
	}

	*trace += fmt.Sprintf("  [tool ok] %s → %s (%v)\n", tc.Name, truncate(result, 150), duration)
	return result, false
}

// GetSessionManager returns the session manager.
func (a *Agent) GetSessionManager() *SessionManager {
	return a.sessions
}

// toRequestTools converts internal tool schemas to OpenAI format.
func toRequestTools(schemas []map[string]any) []openai.Tool {
	out := make([]openai.Tool, len(schemas))
	for i, s := range schemas {
		fn, _ := s["function"].(map[string]any)
		name, _ := fn["name"].(string)
		desc, _ := fn["description"].(string)
		params, _ := fn["parameters"].(map[string]any)

		out[i] = openai.Tool{
			Type: "function",
			Function: &openai.FunctionDefinition{
				Name:        name,
				Description: desc,
				Parameters:  params,
			},
		}
	}
	return out
}

func truncate(s string, n int) string {
	if len(s) <= n {
		return s
	}
	return s[:n] + "..."
}
