<body>

<div class="sidebar">
  <h2>💬 会话列表</h2>
  <div class="session-list" id="session-list"></div>
  <button class="new-session-btn" onclick="newSession()">+ 新建会话</button>
</div>

<div class="main">
  <div class="header">
    <div>
      <h1>momo</h1>
      <div class="subtitle">AI 智能助手 — 支持搜索、计算、文件读取、天气查询</div>
    </div>
  </div>

  <div class="messages" id="messages"></div>

  <div class="status-bar" id="status-bar">
    <span class="status-dot" id="status-dot"></span>
    <span id="status-text">就绪</span>
  </div>

  <div class="input-area">
    <textarea id="input" rows="1" placeholder="输入消息，按 Enter 发送..." onkeydown="if(event.key==='Enter'&&!event.shiftKey){event.preventDefault();send()}"></textarea>
    <button id="send-btn" onclick="send()">发送</button>
  </div>
</div>

<div class="trace-panel" id="trace-panel">
  <h3>🔄 执行追踪</h3>
  <div id="trace-content" style="color:#666;font-size:12px;">暂无追踪信息。</div>
</div>
<button class="trace-toggle-btn" onclick="toggleTrace()">📋 追踪面板</button>

<script>
let currentSession = 'default-' + Date.now();
let traceVisible = false;

function toggleTrace() {
  traceVisible = !traceVisible;
  document.getElementById('trace-panel').classList.toggle('open');
}

function newSession() {
  currentSession = 'session-' + Date.now();
  document.getElementById('messages').innerHTML = '';
  document.getElementById('trace-content').textContent = '暂无追踪信息。';
  document.getElementById('trace-content').className = '';
  loadSessions();
}

function loadSessions() {
  fetch('/api/sessions').then(r=>r.json()).then(data => {
    const list = document.getElementById('session-list');
    if (data.length === 0) data = [{id: currentSession, turns: 0}];
    list.innerHTML = data.map(s =>
      '<div class="session-item' + (s.id === currentSession ? ' active' : '') + '" onclick="switchSession(\'' + s.id + '\')">' +
      '<div class="sid">' + escapeHtml(s.id) + '</div>' +
      '<div class="turns">' + s.turns + ' 轮对话</div></div>'
    ).join('');
  });
}

function switchSession(id) {
  currentSession = id;
  loadSessions();
  loadMessages();
}

function loadMessages() {
  fetch('/api/sessions/' + encodeURIComponent(currentSession)).then(r=>r.json()).then(data => {
    const container = document.getElementById('messages');
    container.innerHTML = '';
    if (!data || data.length === 0) {
      container.innerHTML = '<div style="text-align:center;color:#bbb;margin-top:80px;"><div style="font-size:48px;margin-bottom:16px;">🤖</div><div style="font-size:16px;color:#999;">开始一段对话吧 ✨</div></div>';
      return;
    }
    data.forEach(m => {
      const div = document.createElement('div');
      div.className = 'msg ' + m.role;
      const content = renderContent(m.content, m.role);
      div.innerHTML = '<div class="role-label">' + roleLabel(m.role) + '</div><div class="bubble">' + content + '</div>';
      container.appendChild(div);
    });
    container.scrollTop = container.scrollHeight;
  });
}

function roleLabel(role) {
  switch(role) {
    case 'user': return '🧑 你';
    case 'assistant': return '🤖 momo';
    case 'tool': return '🔧 工具';
    default: return role;
  }
}

function renderContent(text, role) {
  if (!text) return '';
  if (role === 'user' || role === 'tool') return escapeHtml(text);
  // Use marked for markdown rendering (assistant responses)
  try {
    return marked.parse(text, { breaks: true });
  } catch(e) {
    return escapeHtml(text);
  }
}

function escapeHtml(s) {
  if (!s) return '';
  return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g,'<br>');
}

function send() {
  const input = document.getElementById('input');
  const msg = input.value.trim();
  if (!msg) return;
  input.value = '';

  const container = document.getElementById('messages');
  const btn = document.getElementById('send-btn');

  // Remove empty state
  const empty = container.querySelector('[style*="text-align:center"]');
  if (empty) empty.remove();

  // Add user message
  const userDiv = document.createElement('div');
  userDiv.className = 'msg user';
  userDiv.innerHTML = '<div class="role-label">🧑 你</div><div class="bubble">' + escapeHtml(msg) + '</div>';
  container.appendChild(userDiv);
  container.scrollTop = container.scrollHeight;

  // Show loading indicator
  const loadingDiv = document.createElement('div');
  loadingDiv.className = 'msg assistant';
  loadingDiv.innerHTML = '<div class="role-label">🤖 momo</div><div class="bubble"><div class="thinking-indicator"><span class="dot"></span><span class="dot"></span><span class="dot"></span></div></div>';
  container.appendChild(loadingDiv);
  container.scrollTop = container.scrollHeight;

  btn.disabled = true;
  setStatus('busy', '思考中...');

  // Clear trace for new request
  document.getElementById('trace-content').textContent = '';
  document.getElementById('trace-content').className = '';

  const traceContainer = document.getElementById('trace-content');

  // Use SSE for real-time streaming
  fetch('/api/chat/stream', {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({session_id: currentSession, message: msg})
  }).then(response => {
    const reader = response.body.getReader();
    const decoder = new TextDecoder();
    let buffer = '';

    function processChunk() {
      reader.read().then(({done, value}) => {
        if (done) return;

        buffer += decoder.decode(value, {stream: true});
        const lines = buffer.split('\n');
        buffer = lines.pop() || '';

        let eventType = '';
        let eventData = '';

        for (const line of lines) {
          if (line.startsWith('event: ')) {
            eventType = line.slice(7).trim();
          } else if (line.startsWith('data: ')) {
            eventData = line.slice(6).trim();
          } else if (line === '' && eventType && eventData) {
            handleEvent(eventType, eventData);
            eventType = '';
            eventData = '';
          }
        }

        processChunk();
      });
    }

    function handleEvent(type, data) {
      let parsed;
      try { parsed = JSON.parse(data); } catch(e) { return; }

      switch(type) {
        case 'trace':
          if (traceContainer) {
            traceContainer.textContent = parsed.trace || '';
            traceContainer.className = '';
          }
          break;

        case 'result':
          // Remove loading
          const loading = container.querySelector('.thinking-indicator');
          if (loading) {
            const bubble = loading.closest('.bubble');
            if (bubble) bubble.innerHTML = '';
          }

          // Show tool calls
          if (parsed.tool_calls && parsed.tool_calls.length > 0) {
            parsed.tool_calls.forEach(tc => {
              const toolDiv = document.createElement('div');
              toolDiv.className = 'msg tool';
              const icon = tc.is_error ? '❌' : '✅';
              const res = tc.is_error ? escapeHtml(tc.result) : '';
              toolDiv.innerHTML = '<div class="role-label">🔧 工具</div><div class="bubble">' + icon + ' <strong>' + escapeHtml(tc.name) + '</strong>(' + escapeHtml(tc.args) + ')' + res + '</div>';
              container.appendChild(toolDiv);
            });
          }

          // Show assistant response
          if (parsed.content) {
            const asstDiv = document.createElement('div');
            asstDiv.className = 'msg assistant';
            try {
              const html = marked.parse(parsed.content, { breaks: true });
              asstDiv.innerHTML = '<div class="role-label">🤖 momo</div><div class="bubble">' + html + '</div>';
            } catch(e) {
              asstDiv.innerHTML = '<div class="role-label">🤖 momo</div><div class="bubble">' + escapeHtml(parsed.content) + '</div>';
            }
            container.appendChild(asstDiv);
          }

          container.scrollTop = container.scrollHeight;
          loadSessions();
          break;

        case 'error':
          const loading2 = container.querySelector('.thinking-indicator');
          if (loading2) {
            const bubble2 = loading2.closest('.bubble');
            if (bubble2) bubble2.innerHTML = '';
          }
          const errDiv = document.createElement('div');
          errDiv.className = 'msg assistant';
          errDiv.innerHTML = '<div class="role-label">🤖 momo</div><div class="bubble" style="color:#c62828;background:#ffe8e8;">❌ ' + escapeHtml(parsed.error) + '</div>';
          container.appendChild(errDiv);
          container.scrollTop = container.scrollHeight;
          break;

        case 'done':
          setStatus('idle', '就绪');
          break;
      }
    }

    processChunk();
  }).catch(err => {
    const l = container.querySelector('.thinking-indicator');
    if (l) { const b = l.closest('.bubble'); if (b) b.innerHTML = ''; }
    const e = document.createElement('div');
    e.className = 'msg assistant';
    e.innerHTML = '<div class="role-label">🤖 momo</div><div class="bubble" style="color:#c62828;background:#ffe8e8;">❌ 网络错误: ' + escapeHtml(err.message) + '</div>';
    container.appendChild(e);
    container.scrollTop = container.scrollHeight;
  }).finally(() => {
    btn.disabled = false;
    if (loadingDiv.parentNode) loadingDiv.remove();
  });

  // Also send via regular API for session persistence
  fetch('/api/chat', {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({session_id: currentSession, message: msg})
  });
}

function setStatus(state, text) {
  const dot = document.getElementById('status-dot');
  const txt = document.getElementById('status-text');
  dot.className = 'status-dot' + (state === 'busy' ? ' busy' : '');
  txt.textContent = text;
}

// Init
loadSessions();
</script>
</body>
</html>`
