  .trace-step-body .result-value { background: #fff; border: 1px solid #eee; border-radius: 4px; padding: 6px 8px; font-family: 'SF Mono', 'Fira Code', monospace; font-size: 11px; white-space: pre-wrap; word-break: break-all; max-height: 150px; overflow-y: auto; }
  .trace-step-body .duration { color: #999; font-size: 11px; margin-top: 4px; }

  .input-area { padding: 12px 24px 16px; border-top: 1px solid #eee; display: flex; gap: 8px; background: #fafafa; }
  .input-area textarea { flex: 1; padding: 10px 14px; border: 1px solid #ddd; border-radius: 10px; resize: none; font-size: 14px; font-family: inherit; outline: none; min-height: 44px; max-height: 100px; }
  .input-area textarea:focus { border-color: #7c7cff; box-shadow: 0 0 0 2px rgba(124,124,255,0.08); }
  .input-area button { padding: 10px 24px; background: linear-gradient(135deg, #7c7cff, #6a6ae0); color: #fff; border: none; border-radius: 10px; font-size: 14px; cursor: pointer; font-weight: 500; min-width: 72px; }
  .input-area button:hover { background: linear-gradient(135deg, #6a6ae0, #5a5ad0); }
  .input-area button:disabled { background: #ccc; cursor: not-allowed; }

  .thinking-indicator { display: flex; align-items: center; gap: 6px; padding: 4px 0; }
