      if (type === 'trace') {
        // Parse trace text into tool steps
        parseTraceSteps(parsed.trace || '');
      }
      else if (type === 'result') {
        // Remove loading indicator from the assistant bubble
        const loading = asstDiv.querySelector('.thinking-indicator');
        if (loading) loading.remove();

        // Build trace steps HTML
        let traceHtml = renderTraceSteps(currentToolSteps);

        // Render final answer
        let answerHtml = '';
        if (parsed.content) {
          try {
            answerHtml = marked.parse(parsed.content, { breaks: true, gfm: true });
          } catch(e) {
            answerHtml = esc(parsed.content);
          }
        }

        // Insert trace steps before the answer
        const bubble = asstDiv.querySelector('.bubble');
        if (bubble) {
          bubble.innerHTML = traceHtml + answerHtml;
        }

        container.scrollTop = container.scrollHeight;
        loadSessions();
      }
      else if (type === 'error') {
        const loading = asstDiv.querySelector('.thinking-indicator');
        if (loading) loading.remove();
        const bubble = asstDiv.querySelector('.bubble');
        if (bubble) {
          bubble.innerHTML = '<div style="color:#c62828;font-size:13px;"><span style="display:inline-block;width:6px;height:6px;border-radius:50%;background:#ff4d4f;margin-right:6px;vertical-align:middle;"></span>' + esc(parsed.error) + '</div>';
        }
        container.scrollTop = container.scrollHeight;
      }
      else if (type === 'done') {
        btn.disabled = false;
      }
    }

    function parseTraceSteps(traceText) {
      if (!traceText) return;
      const lines = traceText.split('\n');
      const steps = [];
      let currentStep = null;

      for (const line of lines) {
        // Tool call: [tool call] name({"args"})
        const callMatch = line.match(/\[tool call\]\s+(\w+)\((.+)\)/);
        if (callMatch) {
          if (currentStep) steps.push(currentStep);
          currentStep = {
            name: callMatch[1],
            args: callMatch[2],
            result: '',
            duration: '',
            error: false,
            done: false
          };
          continue;
        }

        // Tool ok: [tool ok] name → result (duration)
        const okMatch = line.match(/\[tool ok\]\s+\w+\s+→\s+(.+)\s+\((.+)\)/);
        if (okMatch && currentStep) {
          currentStep.result = okMatch[1];
          currentStep.duration = okMatch[2];
          currentStep.done = true;
          steps.push(currentStep);
          currentStep = null;
          continue;
        }

        // Tool error: [tool error] name(args): error (duration)
        const errMatch = line.match(/\[tool error\]\s+(\w+)\(.+?\):\s*(.+)\s+\((.+)\)/);
        if (errMatch && currentStep) {
          currentStep.result = '❌ ' + errMatch[2];
          currentStep.duration = errMatch[3];
          currentStep.error = true;
          currentStep.done = true;
          steps.push(currentStep);
          currentStep = null;
        }
      }

      if (currentStep && currentStep.done) {
        steps.push(currentStep);
      }

      // Only update if we have new steps
      if (steps.length > 0) {
        currentToolSteps = steps;
      }
    }

    readChunk();
  }).catch(err => {
    const loading = asstDiv.querySelector('.thinking-indicator');
    if (loading) loading.remove();
    const bubble = asstDiv.querySelector('.bubble');
    if (bubble) {
      bubble.innerHTML = '<div style="color:#c62828;font-size:13px;"><span style="display:inline-block;width:6px;height:6px;border-radius:50%;background:#ff4d4f;margin-right:6px;vertical-align:middle;"></span>网络错误: ' + esc(err.message) + '</div>';
    }
    container.scrollTop = container.scrollHeight;
  });
}

function renderTraceSteps(steps) {
  if (!steps || steps.length === 0) return '';

  let html = '<div class="trace-steps">';
  for (const step of steps) {
    const dotClass = step.error ? 'dot-err' : (step.done ? 'dot-ok' : 'dot-run');
    const truncatedResult = step.result.length > 120 ? step.result.substring(0, 120) + '...' : step.result;

    html += '<div class="trace-step" onclick="toggleStep(this)">';
    html += '<div class="trace-step-header">';
    html += '<span class="dot ' + dotClass + '"></span>';
    html += '<span class="tname">' + esc(step.name) + '</span>';
    if (step.duration) html += '<span class="duration">' + esc(step.duration) + '</span>';
    html += '<span class="chevron">▶</span>';
    html += '</div>';
    html += '<div class="trace-step-body">';
    html += '<div class="block-label">参数</div>';
    html += '<div class="block">' + esc(step.args) + '</div>';
    html += '<div class="block-label">结果</div>';
    html += '<div class="block">' + esc(truncatedResult) + '</div>';
    html += '</div>';
    html += '</div>';
  }
  html += '</div>';
  return html;
}"}

{"content": "package web

import (
	"context"
	"encoding/json"
	"fmt"
	"html/template"
	"log"
	"net/http"
	"sync"
	"time"

	"github.com/charmbracelet/crush-agent/internal/agent"
)

type Handler struct {
	agent    *agent.Agent
	mu       sync.Mutex
	sessions map[string]bool
}

func NewHandler(a *agent.Agent) *Handler {
	return &Handler{
		agent:    a,
		sessions: make(map[string]bool),
	}
}

type chatRequest struct {
	SessionID string `json:"session_id"`
	Message   string `json:"message"`
}

type chatResponse struct {
	Content   string           `json:"content"`
	Trace     string           `json:"trace"`
	Turns     int              `json:"turns"`
	ToolCalls []agent.ToolCall `json:"tool_calls,omitempty"`
	Error     string           `json:"error,omitempty"`
}

func (h *Handler) RegisterRoutes(mux *http.ServeMux) {
	mux.HandleFunc("/", h.handleIndex)
	mux.HandleFunc("/api/chat", h.handleChat)
	mux.HandleFunc("/api/chat/stream", h.handleChatStream)
	mux.HandleFunc("/api/sessions", h.handleSessions)
	mux.HandleFunc("/api/sessions/", h.handleSessionDetail)
}

func (h *Handler) handleIndex(w http.ResponseWriter, r *http.Request) {
	if r.URL.Path != "/" {
		http.NotFound(w, r)
		return
	}
	tmpl := template.Must(template.New("index").Parse(indexHTML))
	tmpl.Execute(w, nil)
}

func (h *Handler) handleChat(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}
	var req chatRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, fmt.Sprintf("Invalid request: %v", err), http.StatusBadRequest)
		return
	}
	if req.SessionID == "" {
		req.SessionID = "default"
	}
	if req.Message == "" {
		http.Error(w, "Message is required", http.StatusBadRequest)
		return
	}
	ctx, cancel := context.WithTimeout(r.Context(), 120*time.Second)
	defer cancel()
	result, err := h.agent.Run(ctx, req.SessionID, req.Message)
	resp := chatResponse{}
	if err != nil {
		resp.Error = err.Error()
	} else if result != nil {
		resp.Content = result.Content
		resp.Trace = result.Trace
		resp.Turns = result.Turns
		resp.ToolCalls = result.ToolCalls
		resp.Error = result.Error
	}
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(resp)
}

func (h *Handler) handleChatStream(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}
	var req chatRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, fmt.Sprintf("Invalid request: %v", err), http.StatusBadRequest)
		return
	}
	if req.SessionID == "" {
		req.SessionID = "default"
	}
	if req.Message == "" {
		http.Error(w, "Message is required", http.StatusBadRequest)
		return
	}

	flusher, ok := w.(http.Flusher)
	if !ok {
		http.Error(w, "Streaming not supported", http.StatusInternalServerError)
		return
	}

	w.Header().Set("Content-Type", "text/event-stream")
	w.Header().Set("Cache-Control", "no-cache")
	w.Header().Set("Connection", "keep-alive")

	sendEvent := func(event string, data any) {
		jsonData, _ := json.Marshal(data)
		fmt.Fprintf(w, "event: %s\ndata: %s\n\n", event, jsonData)
		flusher.Flush()
	}

	sendEvent("connected", map[string]string{"session": req.SessionID})

	origOnTrace := h.agent.OnTrace
	h.agent.OnTrace = func(trace string) {
		sendEvent("trace", map[string]string{"trace": trace})
	}
	defer func() { h.agent.OnTrace = origOnTrace }()

	ctx, cancel := context.WithTimeout(r.Context(), 120*time.Second)
	defer cancel()

	result, err := h.agent.Run(ctx, req.SessionID, req.Message)
	if err != nil {
		sendEvent("error", map[string]string{"error": err.Error()})
		return
	}
	if result.Error != "" {
		sendEvent("error", map[string]string{"error": result.Error})
		return
	}
	sendEvent("result", map[string]any{
		"content":    result.Content,
		"turns":      result.Turns,
		"tool_calls": result.ToolCalls,
	})
	sendEvent("done", map[string]string{})
}

func (h *Handler) handleSessions(w http.ResponseWriter, r *http.Request) {
	sessions := h.agent.GetSessionManager().List()
	if sessions == nil {
		sessions = []string{}
	}
	data := make([]map[string]any, len(sessions))
	for i, sid := range sessions {
		s := h.agent.GetSessionManager().Get(sid)
		turns := 0
		if s != nil {
			turns = s.TurnCount
		}
		data[i] = map[string]any{"id": sid, "turns": turns}
	}
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(data)
}

func (h *Handler) handleSessionDetail(w http.ResponseWriter, r *http.Request) {
	sessionID := r.URL.Path[len("/api/sessions/"):]
	s := h.agent.GetSessionManager().Get(sessionID)
	if s == nil {
		http.Error(w, "Session not found", http.StatusNotFound)
		return
	}
	msgs := make([]map[string]any, 0, len(s.Messages))
	for _, m := range s.Messages {
		msgs = append(msgs, map[string]any{
			"role":    m.Role,
			"content": formatMessage(m),
		})
	}
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(msgs)
}

func formatMessage(m agent.Message) string {
	switch m.Role {
	case "user":
		return m.Content
	case "assistant":
		if len(m.ToolCalls) > 0 {
			content := m.Content
			for _, tc := range m.ToolCalls {
				content += fmt.Sprintf("\n\n🔧 调用工具: **%s**\n```json\n%s\n```", tc.Function.Name, tc.Function.Arguments)
			}
			return content
		}
		return m.Content
	case "tool":
		content := m.Content
		if len(content) > 500 {
			content = content[:500] + "..."
		}
		return fmt.Sprintf("📎 工具 [%s] 结果:\n```\n%s\n```", m.ToolName, content)
	case "system":
		return m.Content
	default:
		return m.Content
	}
}

func RunServer(addr string, h *Handler) error {
	mux := http.NewServeMux()
	h.RegisterRoutes(mux)
	log.Printf("🌐 momo AI 助手启动 at http://%s\n", addr)
	return http.ListenAndServe(addr, mux)
}

