<body>
<div class="sidebar">
  <h2>💬 会话</h2>
  <div class="session-list" id="session-list"></div>
  <button class="new-session-btn" onclick="newSession()">+ 新建</button>
</div>
<div class="main">
  <div class="header">
    <h1>momo</h1>
  </div>
  <div class="messages" id="messages"></div>
  <div class="input-area">
    <textarea id="input" rows="1" placeholder="输入消息，按 Enter 发送..." onkeydown="if(event.key==='Enter'&&!event.shiftKey){event.preventDefault();send()}"></textarea>
    <button id="send-btn" onclick="send()">发送</button>
  </div>
</div>

<script>
let currentSession = 'session-' + Date.now();
var currentToolSteps = [];

function newSession() {
  currentSession = 'session-' + Date.now();
  document.getElementById('messages').innerHTML = '';
  loadSessions();
}

function loadSessions() {
  fetch('/api/sessions').then(r=>r.json()).then(data => {
    const list = document.getElementById('session-list');
    if (data.length === 0) data = [{id: currentSession, turns: 0}];
    list.innerHTML = data.map(s =>
      '<div class="session-item' + (s.id === currentSession ? ' active' : '') + '" onclick="switchSession(\'' + s.id + '\')">' +
      '<div class="sid">' + esc(s.id) + '</div></div>'
    ).join('');
  });
}

function switchSession(id) {
  currentSession = id;
  loadSessions();
  loadMessages();
}

function loadMessages() {
  fetch('/api/sessions/' + encodeURIComponent(currentSession)).then(r=>r.json()).then(data => {
    const container = document.getElementById('messages');
    container.innerHTML = '';
    if (!data || data.length === 0) {
      container.innerHTML = '<div style="text-align:center;color:#bbb;margin-top:80px;"><div style="font-size:40px;margin-bottom:12px;">🤖</div><div style="font-size:15px;color:#999;">开始一段对话吧 ✨</div></div>';
      return;
    }
    data.forEach(m => { appendMessage(m.role, m.content); });
  });
}

function appendMessage(role, content) {
  const container = document.getElementById('messages');
  const empty = container.querySelector('[style*="text-align:center"]');
  if (empty) empty.remove();

  const div = document.createElement('div');
  div.className = 'msg ' + role;
  let label = role === 'user' ? '🧑 你' : '🤖 momo';
  let html = '';

  if (role === 'user') {
    html = '<div class="bubble">' + esc(content) + '</div>';
  } else {
    try { html = '<div class="bubble">' + marked.parse(content, { breaks: true, gfm: true }) + '</div>'; }
    catch(e) { html = '<div class="bubble">' + esc(content) + '</div>'; }
  }
  div.innerHTML = '<div class="role-label">' + label + '</div>' + html;
  container.appendChild(div);
  container.scrollTop = container.scrollHeight;
}

function esc(s) {
  if (!s) return '';
  return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g,'<br>');
}

function send() {
  const input = document.getElementById('input');
  const msg = input.value.trim();
  if (!msg) return;
  input.value = '';
  const btn = document.getElementById('send-btn');
  btn.disabled = true;

  const container = document.getElementById('messages');
  const empty = container.querySelector('[style*="text-align:center"]');
  if (empty) empty.remove();

  // Add user message
  const userDiv = document.createElement('div');
  userDiv.className = 'msg user';
  userDiv.innerHTML = '<div class="role-label">🧑 你</div><div class="bubble">' + esc(msg) + '</div>';
  container.appendChild(userDiv);
  container.scrollTop = container.scrollHeight;

  // Create assistant bubble — starts with loading dots
  const asstDiv = document.createElement('div');
  asstDiv.className = 'msg assistant';
  asstDiv.innerHTML = '<div class="role-label">🤖 momo</div><div class="bubble"><div class="thinking-indicator"><span class="dot"></span><span class="dot"></span><span class="dot"></span></div></div>';
  container.appendChild(asstDiv);
  container.scrollTop = container.scrollHeight;

  currentToolSteps = [];
  let firstTrace = true;

  fetch('/api/chat/stream', {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({session_id: currentSession, message: msg})
  }).then(response => {
    const reader = response.body.getReader();
    const decoder = new TextDecoder();
    let buf = '';

    function read() {
      reader.read().then(({done, value}) => {
        if (done) return;
        buf += decoder.decode(value, {stream: true});
        const lines = buf.split('\n');
        buf = lines.pop() || '';

        let evt = '', dat = '';
        for (const l of lines) {
          if (l.startsWith('event: ')) evt = l.slice(7).trim();
          else if (l.startsWith('data: ')) dat = l.slice(6).trim();
          else if (l === '' && evt && dat) { onEvent(evt, dat); evt = ''; dat = ''; }
        }
        read();
      });
    }

    function onEvent(type, data) {
      let p;
      try { p = JSON.parse(data); } catch(e) { return; }

      if (type === 'trace') {
        // First trace: remove loading dots, init live trace container
        if (firstTrace) {
          firstTrace = false;
          const ld = asstDiv.querySelector('.thinking-indicator');
          if (ld) ld.remove();
          const bub = asstDiv.querySelector('.bubble');
          if (bub) bub.innerHTML = '<div class="trace-steps" id="live-trace"></div>';
        }
        // Parse and render live
        currentToolSteps = parseSteps(p.trace || '');
        renderLive();
        container.scrollTop = container.scrollHeight;
      }
      else if (type === 'result') {
