function parseSteps(traceText) {
  if (!traceText) return [];
  const lines = traceText.split('\n');
  const steps = [];
  let cur = null;

  for (const line of lines) {
    const c = line.match(/\[tool call\]\s+(\w+)\((.+)\)/);
    if (c) {
      if (cur) steps.push(cur);
      cur = { name: c[1], args: c[2], result: '', duration: '', error: false, done: false };
      continue;
    }
    const o = line.match(/\[tool ok\]\s+\w+\s+→\s+(.+)\s+\((.+)\)/);
    if (o && cur) {
      cur.result = o[1]; cur.duration = o[2]; cur.done = true;
      steps.push(cur); cur = null;
      continue;
    }
    const e = line.match(/\[tool error\]\s+(\w+)\(.+?\):\s*(.+)\s+\((.+)\)/);
    if (e && cur) {
      cur.result = e[2]; cur.duration = e[3]; cur.error = true; cur.done = true;
      steps.push(cur); cur = null;
    }
  }
  if (cur && cur.done) steps.push(cur);
  return steps;
