  es.addEventListener('response', (e) => {
    const p = JSON.parse(e.data);
    if (p.content && liveAnswerDiv) {
      try { liveAnswerDiv.innerHTML = marked.parse(p.content, { breaks: true, gfm: true }); }
      catch(e) { liveAnswerDiv.innerHTML = esc(p.content); }
    }
    container.scrollTop = container.scrollHeight;
    loadSessions();
  });

  es.addEventListener('server_error', (e) => {
    if (finished) return;
    finished = true;
    let msg = '';
    try { const p = JSON.parse(e.data); msg = p.error || p.message || ''; } catch(e) { msg = '服务器错误'; }
    showError(msg);
    es.close();
    btn.disabled = false;
  });

  es.addEventListener('done', () => {
    if (finished) return;
    finished = true;
    es.close();
    btn.disabled = false;
  });

  // EventSource native error: connection failed (not from our server events)
  es.addEventListener('error', () => {
    if (finished) return;
    finished = true;
    showError('连接中断');
    es.close();
    btn.disabled = false;
  });

  function showError(msg) {
    if (liveAnswerDiv) liveAnswerDiv.innerHTML += '<div style="color:#c62828;font-size:13px;margin-top:4px;"><span style="display:inline-block;width:6px;height:6px;border-radius:50%;background:#ff4d4f;margin-right:6px;vertical-align:middle;"></span>' + esc(msg) + '</div>';
    container.scrollTop = container.scrollHeight;
    // Also handle case where llm_start never fired (loading dots still showing)
    const ld = asstDiv.querySelector('.thinking-indicator');
    if (ld) {
      ld.remove();
      const bub = asstDiv.querySelector('.bubble');
      if (bub) bub.innerHTML = '<div style="color:#c62828;font-size:13px;"><span style="display:inline-block;width:6px;height:6px;border-radius:50%;background:#ff4d4f;margin-right:6px;vertical-align:middle;"></span>' + esc(msg) + '</div>';
    }
  }
}"}

{"content": "package web

import (
	"context"
	"encoding/json"
	"fmt"
	"html/template"
	"log"
	"net/http"
	"sync"
	"time"

	"github.com/charmbracelet/crush-agent/internal/agent"
)

type Handler struct {
	agent    *agent.Agent
	mu       sync.Mutex
	sessions map[string]bool
}

func NewHandler(a *agent.Agent) *Handler {
	return &Handler{
		agent:    a,
		sessions: make(map[string]bool),
	}
}

type chatRequest struct {
	SessionID string `json:"session_id"`
	Message   string `json:"message"`
}

type chatResponse struct {
	Content   string           `json:"content"`
	Trace     string           `json:"trace"`
	Turns     int              `json:"turns"`
	ToolCalls []agent.ToolCall `json:"tool_calls,omitempty"`
	Error     string           `json:"error,omitempty"`
}

func (h *Handler) RegisterRoutes(mux *http.ServeMux) {
	mux.HandleFunc("/", h.handleIndex)
	mux.HandleFunc("/api/chat", h.handleChat)
	mux.HandleFunc("/api/sessions", h.handleSessions)
	mux.HandleFunc("/api/sessions/", h.handleSessionDetail)
}

func (h *Handler) handleIndex(w http.ResponseWriter, r *http.Request) {
	if r.URL.Path != "/" {
		http.NotFound(w, r)
		return
	}
	tmpl := template.Must(template.New("index").Parse(indexHTML))
	tmpl.Execute(w, nil)
}

func (h *Handler) handleChat(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}
	var req chatRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, fmt.Sprintf("Invalid request: %v", err), http.StatusBadRequest)
		return
	}
	if req.SessionID == "" {
		req.SessionID = "default"
	}
	if req.Message == "" {
		http.Error(w, "Message is required", http.StatusBadRequest)
		return
	}
	ctx, cancel := context.WithTimeout(r.Context(), 120*time.Second)
	defer cancel()
	result, err := h.agent.Run(ctx, req.SessionID, req.Message)
	resp := chatResponse{}
	if err != nil {
		resp.Error = err.Error()
	} else if result != nil {
		resp.Content = result.Content
		resp.Trace = result.Trace
		resp.Turns = result.Turns
		resp.ToolCalls = result.ToolCalls
		resp.Error = result.Error
	}
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(resp)
}

func (h *Handler) handleSessions(w http.ResponseWriter, r *http.Request) {
	sessions := h.agent.GetSessionManager().List()
	if sessions == nil {
		sessions = []string{}
	}
	data := make([]map[string]any, len(sessions))
	for i, sid := range sessions {
		s := h.agent.GetSessionManager().Get(sid)
		turns := 0
		if s != nil {
			turns = s.TurnCount
		}
		data[i] = map[string]any{"id": sid, "turns": turns}
	}
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(data)
}

func (h *Handler) handleSessionDetail(w http.ResponseWriter, r *http.Request) {
	sessionID := r.URL.Path[len("/api/sessions/"):]
	s := h.agent.GetSessionManager().Get(sessionID)
	if s == nil {
		http.Error(w, "Session not found", http.StatusNotFound)
		return
	}
	msgs := make([]map[string]any, 0, len(s.Messages))
	for _, m := range s.Messages {
		content := m.Content
		if m.Role == "assistant" && len(m.ToolCalls) > 0 {
			for _, tc := range m.ToolCalls {
				content += fmt.Sprintf("\n\n🔧 Calling tool: **%s**\n\`\`\`json\n%s\n\`\`\`", tc.Function.Name, tc.Function.Arguments)
			}
		} else if m.Role == "tool" {
			if len(content) > 500 {
				content = content[:500] + "..."
			}
			content = fmt.Sprintf("📎 Tool [%s] result:\n\`\`\`\n%s\n\`\`\`", m.ToolName, content)
		}
		msgs = append(msgs, map[string]any{"role": m.Role, "content": content})
	}
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(msgs)
}

func RunServer(addr string, h *Handler) error {
	mux := http.NewServeMux()
	h.RegisterRoutes(mux)
	log.Printf("🌐 momo AI 助手启动 at http://%s\n", addr)
	return http.ListenAndServe(addr, mux)
}

