<body>
<div class="sidebar">
  <h2>💬 会话</h2>
  <div class="session-list" id="session-list"></div>
  <button class="new-session-btn" onclick="newSession()">+ 新建</button>
</div>
<div class="main">
  <div class="header">
    <h1>momo</h1>
  </div>
  <div class="messages" id="messages"></div>
  <div class="input-area">
    <textarea id="input" rows="1" placeholder="输入消息，按 Enter 发送..." onkeydown="if(event.key==='Enter'&&!event.shiftKey){event.preventDefault();send()}"></textarea>
    <button id="send-btn" onclick="send()">发送</button>
  </div>
</div>

<script>
let currentSession = 'session-' + Date.now();

function newSession() {
  currentSession = 'session-' + Date.now();
  document.getElementById('messages').innerHTML = '';
  loadSessions();
}

function loadSessions() {
  fetch('/api/sessions').then(r=>r.json()).then(data => {
    const list = document.getElementById('session-list');
    if (data.length === 0) data = [{id: currentSession, turns: 0}];
    list.innerHTML = data.map(s =>
      '<div class="session-item' + (s.id === currentSession ? ' active' : '') + '" onclick="switchSession(\'' + s.id + '\')">' +
      '<div class="sid">' + esc(s.id) + '</div></div>'
    ).join('');
  });
}

function switchSession(id) {
  currentSession = id;
  loadSessions();
  loadMessages();
}

function loadMessages() {
  fetch('/api/sessions/' + encodeURIComponent(currentSession)).then(r=>r.json()).then(data => {
    const container = document.getElementById('messages');
    container.innerHTML = '';
    if (!data || data.length === 0) {
      container.innerHTML = '<div style="text-align:center;color:#bbb;margin-top:80px;"><div style="font-size:40px;margin-bottom:12px;">🤖</div><div style="font-size:15px;color:#999;">开始一段对话吧 ✨</div></div>';
      return;
    }
    data.forEach(m => { appendMessage(m.role, m.content); });
  });
}

function appendMessage(role, content) {
  const container = document.getElementById('messages');
  const empty = container.querySelector('[style*="text-align:center"]');
  if (empty) empty.remove();
  const div = document.createElement('div');
  div.className = 'msg ' + role;
  let label = role === 'user' ? '🧑 你' : '🤖 momo';
  let html = '';
  if (role === 'user') {
    html = '<div class="bubble">' + esc(content) + '</div>';
  } else {
    try { html = '<div class="bubble">' + marked.parse(content, { breaks: true, gfm: true }) + '</div>'; }
    catch(e) { html = '<div class="bubble">' + esc(content) + '</div>'; }
  }
  div.innerHTML = '<div class="role-label">' + label + '</div>' + html;
  container.appendChild(div);
  container.scrollTop = container.scrollHeight;
}

function esc(s) {
  if (!s) return '';
  return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g,'<br>');
}

function send() {
  const input = document.getElementById('input');
  const msg = input.value.trim();
  if (!msg) return;
  input.value = '';
  const btn = document.getElementById('send-btn');
  btn.disabled = true;

  const container = document.getElementById('messages');
  const empty = container.querySelector('[style*="text-align:center"]');
  if (empty) empty.remove();

  // Add user message
  const userDiv = document.createElement('div');
  userDiv.className = 'msg user';
  userDiv.innerHTML = '<div class="role-label">🧑 你</div><div class="bubble">' + esc(msg) + '</div>';
  container.appendChild(userDiv);
  container.scrollTop = container.scrollHeight;

  // Assistant bubble: loading dots + trace + answer containers
  const asstDiv = document.createElement('div');
  asstDiv.className = 'msg assistant';
  asstDiv.innerHTML = '<div class="role-label">🤖 momo</div><div class="bubble"><div class="thinking-indicator"><span class="dot"></span><span class="dot"></span><span class="dot"></span></div><div class="trace-steps"></div><div class="answer-container"></div></div>';
  container.appendChild(asstDiv);
  container.scrollTop = container.scrollHeight;

  const loadingEl = asstDiv.querySelector('.thinking-indicator');
  const traceEl = asstDiv.querySelector('.trace-steps');
  const answerEl = asstDiv.querySelector('.answer-container');

  // Poll session messages to show tool calls in real-time
  const pollTimer = setInterval(() => {
    fetch('/api/sessions/' + encodeURIComponent(currentSession)).then(r=>r.json()).then(data => {
      if (!data || data.length < 2) return;
      const last = data[data.length - 1];
      // If last assistant message has tool calls, show them
      if (last && last.role === 'assistant' && last.content.includes('🔧')) {
        const toolMatch = last.content.match(/🔧.*?\*\*(\w+)\*\*/);
        if (toolMatch) {
          loadingEl.style.display = 'none';
          traceEl.innerHTML = '<div class="trace-step"><div class="trace-step-header"><span class="dot dot-run"></span><span class="tname">🔧 ' + esc(toolMatch[1]) + '</span><span class="duration">运行中...</span></div></div>';
        }
      }
    }).catch(() => {});
  }, 500);

  // Main request
  fetch('/api/chat', {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({session_id: currentSession, message: msg})
  })
  .then(r => r.json())
  .then(data => {
    clearInterval(pollTimer);
    if (loadingEl) loadingEl.remove();

    // Show error
    if (data.error) {
      answerEl.innerHTML = '<div style="color:#c62828;font-size:13px;"><span style="display:inline-block;width:6px;height:6px;border-radius:50%;background:#ff4d4f;margin-right:6px;vertical-align:middle;"></span>' + esc(data.error) + '</div>';
      container.scrollTop = container.scrollHeight;
      btn.disabled = false;
      return;
    }

    // Show response
    if (data.content) {
      try { answerEl.innerHTML = marked.parse(data.content, { breaks: true, gfm: true }); }
      catch(e) { answerEl.innerHTML = esc(data.content); }
    }
    container.scrollTop = container.scrollHeight;
    loadSessions();
    btn.disabled = false;
  })
  .catch(err => {
    clearInterval(pollTimer);
    if (loadingEl) loadingEl.remove();
    answerEl.innerHTML = '<div style="color:#c62828;font-size:13px;"><span style="display:inline-block;width:6px;height:6px;border-radius:50%;background:#ff4d4f;margin-right:6px;vertical-align:middle;"></span>网络错误: ' + esc(err.message) + '</div>';
    container.scrollTop = container.scrollHeight;
    btn.disabled = false;
  });
}

function toggleStep(el) {
  el.classList.toggle('open');
}

loadSessions();
</script>
</body>
</html>`
