<div class="sidebar">
  <h2>💬 会话</h2>
  <div class="session-list" id="session-list"></div>
  <button class="new-session-btn" onclick="newSession()">+ 新建</button>
</div>
<div class="main">
  <div class="header"><h1>momo</h1></div>
  <div class="messages" id="messages"></div>
  <div class="input-area">
    <textarea id="input" rows="1" placeholder="输入消息，按 Enter 发送..." onkeydown="if(event.key==='Enter'&&!event.shiftKey){event.preventDefault();send()}"></textarea>
    <button id="send-btn" onclick="send()">发送</button>
  </div>
</div>
<script>
const STORAGE_KEY = 'momo_messages';

function loadFromStorage() {
  try { return JSON.parse(localStorage.getItem(STORAGE_KEY) || '{}'); } catch(e) { return {}; }
}
function saveToStorage(data) {
  try { localStorage.setItem(STORAGE_KEY, JSON.stringify(data)); } catch(e) {}
}

function getMessages() {
  const all = loadFromStorage();
  return all[currentSession] || [];
}
function setMessages(msgs) {
  const all = loadFromStorage();
  all[currentSession] = msgs;
  saveToStorage(all);
}

let currentSession = localStorage.getItem('momo_session') || 'default';
localStorage.setItem('momo_session', currentSession);

function newSession() {
  currentSession = 'session-' + Date.now();
  localStorage.setItem('momo_session', currentSession);
  renderMessages();
  loadSessions();
}

function loadSessions() {
  const all = loadFromStorage();
  const list = document.getElementById('session-list');
  const sessions = Object.keys(all);
  if (sessions.length === 0) sessions.push('default');
  list.innerHTML = sessions.map(s =>
    '<div class="session-item' + (s === currentSession ? ' active' : '') + '" onclick="switchSession(\'' + s + '\')">' +
    '<div class="sid">' + esc(s) + '</div></div>'
  ).join('');
}

function switchSession(id) {
  currentSession = id;
  localStorage.setItem('momo_session', currentSession);
  loadSessions();
  renderMessages();
}

function renderMessages() {
  const container = document.getElementById('messages');
  const msgs = getMessages();
  container.innerHTML = '';
  if (msgs.length === 0) {
    container.innerHTML = '<div style="text-align:center;color:#bbb;margin-top:80px;"><div style="font-size:40px;margin-bottom:12px;">🤖</div><div style="font-size:15px;color:#999;">开始一段对话吧 ✨</div></div>';
    return;
  }
  msgs.forEach(m => {
    const div = document.createElement('div');
    div.className = 'msg ' + m.role;
    let label = m.role === 'user' ? '🧑 你' : '🤖 momo';
    let html = '';
    if (m.role === 'user') {
      html = '<div class="bubble">' + esc(m.content) + '</div>';
    } else {
      try { html = '<div class="bubble">' + marked.parse(m.content, { breaks: true, gfm: true }) + '</div>'; }
      catch(e) { html = '<div class="bubble">' + esc(m.content) + '</div>'; }
    }
    div.innerHTML = '<div class="role-label">' + label + '</div>' + html;
    container.appendChild(div);
  });
  container.scrollTop = container.scrollHeight;
}

function esc(s) {
  if (!s) return '';
  return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g,'<br>');
}

function send() {
  const input = document.getElementById('input');
  const msg = input.value.trim();
  if (!msg) return;
  input.value = '';
  const btn = document.getElementById('send-btn');
  btn.disabled = true;

  const container = document.getElementById('messages');
  container.querySelector('[style*="text-align:center"]')?.remove();

  // Add user message to UI + storage
  const msgs = getMessages();
  msgs.push({ role: 'user', content: msg });
  setMessages(msgs);

  const userDiv = document.createElement('div');
  userDiv.className = 'msg user';
  userDiv.innerHTML = '<div class="role-label">🧑 你</div><div class="bubble">' + esc(msg) + '</div>';
  container.appendChild(userDiv);
  container.scrollTop = container.scrollHeight;

  // Loading dots
  const loadingDiv = document.createElement('div');
  loadingDiv.className = 'msg assistant';
  loadingDiv.id = 'loading-msg';
  loadingDiv.innerHTML = '<div class="role-label">🤖 momo</div><div class="bubble"><div class="thinking-indicator"><span class="dot"></span><span class="dot"></span><span class="dot"></span></div></div>';
  container.appendChild(loadingDiv);
  container.scrollTop = container.scrollHeight;

  // Poll for tool call updates
  let pollTimer = setInterval(() => {
    fetch('/api/sessions/' + encodeURIComponent(currentSession))
      .then(r => r.json())
      .then(data => {
        if (!data || data.length === 0) return;
        const last = data[data.length - 1];
        if (last.role === 'assistant') {
          // Check for tool calls in raw content
          if (last.content && last.content.includes('🔧')) {
            const toolMatch = last.content.match(/\*\*(\w+)\*\*/);
            if (toolMatch) {
              const loadingEl = document.getElementById('loading-msg');
              if (loadingEl) {
                loadingEl.innerHTML = '<div class="role-label">🤖 momo</div><div class="bubble"><div class="trace-steps"><div class="trace-step"><div class="trace-step-header"><span class="dot dot-run"></span><span class="tname">🔧 ' + esc(toolMatch[1]) + '</span><span class="duration">运行中...</span></div></div></div><div class="thinking-indicator" style="margin-top:4px;"><span class="dot"></span><span class="dot"></span><span class="dot"></span></div></div>';
              }
              clearInterval(pollTimer);
              pollTimer = setInterval(() => {
                fetch('/api/sessions/' + encodeURIComponent(currentSession))
                  .then(r => r.json())
                  .then(d2 => {
                    const l2 = d2 ? d2[d2.length - 1] : null;
                    if (l2 && l2.role === 'assistant' && l2.content && !l2.content.includes('🔧')) {
                      clearInterval(pollTimer);
                    }
                  }).catch(() => {});
              }, 800);
            }
          }
        }
      }).catch(() => {});
  }, 600);

  // Main request
  fetch('/api/chat', {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({session_id: currentSession, message: msg})
  })
  .then(r => r.json())
  .then(data => {
    clearInterval(pollTimer);
    document.getElementById('loading-msg')?.remove();

    if (data.error) {
      const errDiv = document.createElement('div');
      errDiv.className = 'msg assistant';
      errDiv.innerHTML = '<div class="role-label">🤖 momo</div><div class="bubble" style="color:#c62828;">❌ ' + esc(data.error) + '</div>';
      container.appendChild(errDiv);
      const msgs2 = getMessages();
      msgs2.push({ role: 'assistant', content: '错误: ' + data.error });
      setMessages(msgs2);
    } else if (data.content) {
      const asstDiv = document.createElement('div');
      asstDiv.className = 'msg assistant';
      let html = '';
      try { html = '<div class="bubble">' + marked.parse(data.content, { breaks: true, gfm: true }) + '</div>'; }
      catch(e) { html = '<div class="bubble">' + esc(data.content) + '</div>'; }
      asstDiv.innerHTML = '<div class="role-label">🤖 momo</div>' + html;
      container.appendChild(asstDiv);
      const msgs2 = getMessages();
      msgs2.push({ role: 'assistant', content: data.content });
      setMessages(msgs2);
    }

    container.scrollTop = container.scrollHeight;
    loadSessions();
    btn.disabled = false;
  })
  .catch(err => {
    clearInterval(pollTimer);
    document.getElementById('loading-msg')?.remove();
    const errDiv = document.createElement('div');
    errDiv.className = 'msg assistant';
    errDiv.innerHTML = '<div class="role-label">🤖 momo</div><div class="bubble" style="color:#c62828;">❌ 网络错误: ' + esc(err.message) + '</div>';
    container.appendChild(errDiv);
    container.scrollTop = container.scrollHeight;
    btn.disabled = false;
  });
}

loadSessions();
renderMessages();
</script>
</body>
