<script>
const STORAGE = 'momo_msgs';
function loadS() { try { return JSON.parse(localStorage.getItem(STORAGE)||'{}'); } catch(e) { return {}; } }
function saveS(d) { try { localStorage.setItem(STORAGE,JSON.stringify(d)); } catch(e) {} }
function getMs() { const a=loadS(); return a[currentSession]||[]; }
function setMs(m) { const a=loadS(); a[currentSession]=m; saveS(a); }

let currentSession = localStorage.getItem('momo_cur') || 'default';
localStorage.setItem('momo_cur', currentSession);

function newSession() {
  currentSession = 's-' + Date.now();
  localStorage.setItem('momo_cur', currentSession);
  renderMs(); listS();
}

function listS() {
  const a=loadS(); const k=Object.keys(a); if(!k.length) k.push('default');
  document.getElementById('session-list').innerHTML = k.map(s =>
    '<div class="session-item'+(s===currentSession?' active':'')+'" onclick="switchS(\''+s+'\')"><div class="sid">'+esc(s)+'</div></div>'
  ).join('');
